<!DOCTYPE html>
<html lang="id">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Portal Olimpiade Sains FST</title>
<link rel="stylesheet" href="style.css">
<style>
</style>
</head>
<body>

<!-- ============================================================
  PAGE 1: LANDING
============================================================ -->
<div id="page-landing" class="page active">
  <nav class="landing-nav">
    <div class="nav-logo" style="display:flex;align-items:center;gap:10px;">
      <img src="data:image/png;base64," alt="Logo Unpatti" style="height:48px;width:auto;" />
      <img src="data:image/png;base64," alt="Logo FST" style="height:48px;width:auto;" />
      <div class="logo-text">
        <span class="name">Portal Olimpiade Sains</span>
        <span class="sub">FST</span>
      </div>
    </div>
    <div class="nav-actions">
      <button class="btn btn-outline" onclick="showPage('page-login')">Masuk</button>
      <button class="btn btn-orange" onclick="showPage('page-register')">Daftar Sekarang</button>
    </div>
  </nav>

  <div class="landing-hero">
    <h1>Selamat Datang di Portal Olimpiade Sains</h1>
    <p>Daftar dan ikuti kompetisi sains tingkat nasional. Tunjukkan kemampuan terbaikmu!</p>
    <div class="hero-btns">
      <button class="btn btn-orange" style="padding:12px 28px;font-size:15px;" onclick="showPage('page-register')">Daftar Sebagai Peserta</button>
      <button class="btn btn-outline" style="padding:12px 28px;font-size:15px;" onclick="showPage('page-admin-login')">Login Admin</button>
    </div>
    
<div class="landing-about" style="margin-top:36px;max-width:900px;margin-left:auto;margin-right:auto;padding:0 20px;box-sizing:border-box;">
      <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:16px;box-sizing:border-box;">
        <div style="background:#fff;border-radius:12px;padding:20px;box-sizing:border-box;">
          <div style="width:44px;height:44px;border-radius:10px;background:var(--orange-bg);display:flex;align-items:center;justify-content:center;margin-bottom:12px;">
            <svg viewBox="0 0 24 24" style="width:22px;height:22px;fill:var(--orange);"><path d="M12 14l9-5-9-5-9 5 9 5z"/><path d="M12 14l6.16-3.42A8.5 8.5 0 0112 21a8.5 8.5 0 01-6.16-10.42L12 14z"/></svg>
          </div>
          <h3 style="font-size:15px;margin-bottom:6px;">Untuk Siapa</h3>
          <p style="font-size:13px;color:var(--text-gray);line-height:1.6;">
            Siswa jenjang SD, SMP, dan SMA/Sederajat se-Provinsi Maluku.
          </p>
        </div>
        <div style="background:#fff;border-radius:12px;padding:20px;box-sizing:border-box;">
          <div style="width:44px;height:44px;border-radius:10px;background:var(--blue-bg);display:flex;align-items:center;justify-content:center;margin-bottom:12px;">
            <svg viewBox="0 0 24 24" style="width:22px;height:22px;fill:var(--blue);"><path d="M9 17H7v-7h2v7zm4 0h-2V7h2v10zm4 0h-2v-4h2v4zm2.5 4.5h-15c-.55 0-1-.45-1-1V3.5c0-.55.45-1 1-1h15c.55 0 1 .45 1 1V20.5c0 .55-.45 1-1 1z"/></svg>
          </div>
          <h3 style="font-size:15px;margin-bottom:6px;">Bidang Lomba</h3>
          <p style="font-size:13px;color:var(--text-gray);line-height:1.6;">
            Matematika, Fisika, Kimia, Biologi, dan Komputer.
          </p>
        </div>
        <div style="background:#fff;border-radius:12px;padding:20px;box-sizing:border-box;">
          <div style="width:44px;height:44px;border-radius:10px;background:var(--green-bg);display:flex;align-items:center;justify-content:center;margin-bottom:12px;">
            <svg viewBox="0 0 24 24" style="width:22px;height:22px;fill:var(--green);"><path d="M5 16L3 5l5.5 5L12 4l3.5 6L21 5l-2 11H5zm14 3a1 1 0 01-1 1H6a1 1 0 010-2h12a1 1 0 011 1z"/></svg>
          </div>
          <h3 style="font-size:15px;margin-bottom:6px;">Penghargaan</h3>
          <p style="font-size:13px;color:var(--text-gray);line-height:1.6;">
            Pemenang berkesempatan mewakili Maluku di ajang nasional.
          </p>
        </div>
      </div>
    </div>

    <div class="landing-contact" style="margin-top:36px;">
      <h2>Informasi Kontak</h2>
      <div class="contact-item">
        <div class="c-icon"><svg viewBox="0 0 24 24"><path d="M6.62 10.79c1.44 2.83 3.76 5.14 6.59 6.59l2.2-2.2c.27-.27.67-.36 1.02-.24 1.12.37 2.33.57 3.57.57.55 0 1 .45 1 1V20c0 .55-.45 1-1 1-9.39 0-17-7.61-17-17 0-.55.45-1 1-1h3.5c.55 0 1 .45 1 1 0 1.25.2 2.45.57 3.57.11.35.03.74-.25 1.02l-2.2 2.2z"/></svg></div>
        <div>
          <div class="c-label">Telepon</div>
          <div class="c-val">+62 811 123 456</div>
        </div>
      </div>
      <div class="contact-item">
        <div class="c-icon"><svg viewBox="0 0 24 24"><path d="M20 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V6c0-1.1-.9-2-2-2zm0 4l-8 5-8-5V6l8 5 8-5v2z"/></svg></div>
        <div>
          <div class="c-label">Email</div>
          <div class="c-val">olimpiade@fst.ac.id</div>
        </div>
      </div>
      <div class="contact-item">
        <div class="c-icon"><svg viewBox="0 0 24 24"><path d="M11.99 2C6.47 2 2 6.48 2 12s4.47 10 9.99 10C17.52 22 22 17.52 22 12S17.52 2 11.99 2zm-1 17.93c-3.95-.49-7-3.85-7-7.93 0-.62.08-1.21.21-1.79L9 15v1c0 1.1.9 2 2 2v1.93zm6.9-2.54c-.26-.81-1-1.39-1.9-1.39h-1v-3c0-.55-.45-1-1-1H8v-2h2c.55 0 1-.45 1-1V7h2c1.1 0 2-.9 2-2v-.41c2.93 1.19 5 4.06 5 7.41 0 2.08-.8 3.97-2.1 5.39z"/></svg></div>
        <div>
          <div class="c-label">Website</div>
          <div class="c-val">www.fst.ac.id</div>
        </div>
      </div>
      <div class="contact-item">
        <div class="c-icon"><svg viewBox="0 0 24 24"><path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7zm0 9.5c-1.38 0-2.5-1.12-2.5-2.5s1.12-2.5 2.5-2.5 2.5 1.12 2.5 2.5-1.12 2.5-2.5 2.5z"/></svg></div>
        <div>
          <div class="c-label">Alamat</div>
          <div class="c-val">Fakultas Sains dan Teknologi,Universitas Pattimura</div>
        </div>
      </div>
    </div>
  </div>
  <button class="help-btn">?</button>
</div>


<!-- ============================================================
  PAGE 2: REGISTER
============================================================ -->
<div id="page-register" class="page" style='background: linear-gradient(rgba(0,0,0,0.20),rgba(0,0,0,0.45)), url("data:image/png;base64,") center/cover no-repeat; align-items:center; justify-content:center; padding:40px 16px;'>
  <div class="auth-logo">
    <div class="logo-icon large">
      <svg viewBox="0 0 24 24"><path d="M12 3L1 9l4 2.18v6L12 21l7-3.82v-6l2-1.09V17h2V9L12 3zm6.82 6L12 12.72 5.18 9 12 5.28 18.82 9zM17 15.99l-5 2.73-5-2.73v-3.72L12 15l5-2.73v3.72z"/></svg>
    </div>
    <div class="logo-text">
      <span class="name" style="font-size:22px;">Portal Olimpiade Sains</span>
      <span class="sub">FST</span>
    </div>
  </div>
  <div class="auth-card">
    <h2>Daftar Akun</h2>
    <div class="field">
      <label>Nama Lengkap</label>
      <input type="text" id="reg-nama" placeholder="Masukkan nama lengkap">
    </div>
    <div class="field">
      <label>Email</label>
      <input type="email" id="reg-email" placeholder="Masukkan email">
    </div>
    <div class="field">
      <label>Password</label>
      <input type="password" id="reg-pass" placeholder="Masukkan password">
    </div>
    <div class="field">
      <label>Konfirmasi Password</label>
      <input type="password" id="reg-pass2" placeholder="Masukkan ulang password">
    </div>
    <button class="btn btn-orange btn-full" onclick="doRegister()">Daftar</button>
    <div class="auth-footer">Sudah punya akun? <a onclick="showPage('page-login')">Masuk</a></div>
    <div style="text-align:center;margin-top:12px;">
      <a onclick="showPage('page-landing')" style="font-size:13px;color:var(--text-gray);cursor:pointer;display:inline-flex;align-items:center;gap:5px;">
        <svg viewBox="0 0 24 24" style="width:14px;height:14px;fill:currentColor;"><path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/></svg>
        Kembali ke Halaman Utama
      </a>
    </div>
  </div>
</div>


<!-- ============================================================
  PAGE 4: LOGIN PESERTA
============================================================ -->
<div id="page-login" class="page" style="flex-direction:row;">
  <div class="login-left">
    <div class="l-logo">
      <div class="logo-icon" style="background:rgba(255,255,255,0.25);width:52px;height:52px;border-radius:14px;">
        <svg viewBox="0 0 24 24" style="width:28px;height:28px;fill:white;"><path d="M12 3L1 9l4 2.18v6L12 21l7-3.82v-6l2-1.09V17h2V9L12 3zm6.82 6L12 12.72 5.18 9 12 5.28 18.82 9zM17 15.99l-5 2.73-5-2.73v-3.72L12 15l5-2.73v3.72z"/></svg>
      </div>
      <div class="logo-text">
        <span style="font-size:22px;font-weight:800;color:white;">Portal Olimpiade Sains</span>
        <span style="color:rgba(255,255,255,0.8);font-size:13px;">Fakultas Sains dan Teknologi</span>
      </div>
    </div>
    <div class="l-contact-item">
      <div class="l-c-icon"><svg viewBox="0 0 24 24"><path d="M6.62 10.79c1.44 2.83 3.76 5.14 6.59 6.59l2.2-2.2c.27-.27.67-.36 1.02-.24 1.12.37 2.33.57 3.57.57.55 0 1 .45 1 1V20c0 .55-.45 1-1 1-9.39 0-17-7.61-17-17 0-.55.45-1 1-1h3.5c.55 0 1 .45 1 1 0 1.25.2 2.45.57 3.57.11.35.03.74-.25 1.02l-2.2 2.2z"/></svg></div>
      <div><div class="l-c-label">Telepon</div><div class="l-c-val">+62 811 123 456</div></div>
    </div>
    <div class="l-contact-item">
      <div class="l-c-icon"><svg viewBox="0 0 24 24"><path d="M20 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V6c0-1.1-.9-2-2-2zm0 4l-8 5-8-5V6l8 5 8-5v2z"/></svg></div>
      <div><div class="l-c-label">Email</div><div class="l-c-val">olimpiade@fst.ac.id</div></div>
    </div>
    <div class="l-contact-item">
      <div class="l-c-icon"><svg viewBox="0 0 24 24"><path d="M11.99 2C6.47 2 2 6.48 2 12s4.47 10 9.99 10C17.52 22 22 17.52 22 12S17.52 2 11.99 2zm-1 17.93c-3.95-.49-7-3.85-7-7.93 0-.62.08-1.21.21-1.79L9 15v1c0 1.1.9 2 2 2v1.93zm6.9-2.54c-.26-.81-1-1.39-1.9-1.39h-1v-3c0-.55-.45-1-1-1H8v-2h2c.55 0 1-.45 1-1V7h2c1.1 0 2-.9 2-2v-.41c2.93 1.19 5 4.06 5 7.41 0 2.08-.8 3.97-2.1 5.39z"/></svg></div>
      <div><div class="l-c-label">Website</div><div class="l-c-val">www.fst.ac.id</div></div>
    </div>
    <div class="l-contact-item">
      <div class="l-c-icon"><svg viewBox="0 0 24 24"><path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7zm0 9.5c-1.38 0-2.5-1.12-2.5-2.5s1.12-2.5 2.5-2.5 2.5 1.12 2.5 2.5-1.12 2.5-2.5 2.5z"/></svg></div>
      <div><div class="l-c-label">Alamat</div><div class="l-c-val">Fakultas Sains dan Teknologi, Universitas Pattimura</div></div>
    </div>
  </div>
  <div class="login-right">
    <div class="login-form-box">
      <h2>Masuk</h2>
      <div class="field">
        <label>Email</label>
        <input type="email" id="login-email" placeholder="Masukkan email">
      </div>
      <div class="field">
        <label>Password</label>
        <input type="password" id="login-pass" placeholder="Masukkan password">
        <span class="lupa-pw" onclick="showResetPassword()">
    Lupa Password?
</span>
<script>
function showResetPassword() {
    const email = prompt("Masukkan email yang terdaftar:");

    if (!email) return;

    alert("Link reset password telah dikirim ke email: " + email);
}
</script>
      </div>
      <button class="btn btn-orange btn-full" onclick="doLogin()">Masuk</button>
      <div class="auth-footer" style="margin-top:20px;">Belum punya akun? <a onclick="showPage('page-register')">Daftar akun</a></div>
      <div style="text-align:center;margin-top:12px;">
        <a onclick="showPage('page-landing')" style="font-size:13px;color:var(--text-gray);cursor:pointer;display:inline-flex;align-items:center;gap:5px;">
          <svg viewBox="0 0 24 24" style="width:14px;height:14px;fill:currentColor;"><path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/></svg>
          Kembali ke Halaman Utama
        </a>
      </div>
    </div>
  </div>
</div>


<!-- ============================================================
  PAGE 5: DASHBOARD PESERTA
============================================================ -->
<div id="page-dashboard" class="page" style="background:#F9FAFB;">
  <div class="app-layout">
    <!-- SIDEBAR -->
    <aside class="sidebar">
      <div class="s-logo">
        <div class="logo-icon" style="width:36px;height:36px;"><svg viewBox="0 0 24 24"><path d="M12 3L1 9l4 2.18v6L12 21l7-3.82v-6l2-1.09V17h2V9L12 3zm6.82 6L12 12.72 5.18 9 12 5.28 18.82 9zM17 15.99l-5 2.73-5-2.73v-3.72L12 15l5-2.73v3.72z"/></svg></div>
        <div class="logo-text"><span class="name">Portal<br>Olimpiade</span><span class="sub">FST</span></div>
      </div>
      <div class="s-user">
        <div class="s-user-avatar"><svg viewBox="0 0 24 24"><path d="M12 12c2.21 0 4-1.79 4-4s-1.79-4-4-4-4 1.79-4 4 1.79 4 4 4zm0 2c-2.67 0-8 1.34-8 4v2h16v-2c0-2.66-5.33-4-8-4z"/></svg></div>
        <div><div class="s-user-name" id="sidebar-name">Peserta</div><div class="s-user-role">Peserta</div></div>
      </div>
      <nav class="s-nav">
        <div class="s-nav-item active" id="nav-dashboard" onclick="switchTab('dashboard')">
          <svg viewBox="0 0 24 24"><path d="M3 13h8V3H3v10zm0 8h8v-6H3v6zm10 0h8V11h-8v10zm0-18v6h8V3h-8z"/></svg>
          Dashboard
        </div>
        <div class="s-nav-item" id="nav-profil" onclick="switchTab('profil')">
          <svg viewBox="0 0 24 24"><path d="M12 12c2.21 0 4-1.79 4-4s-1.79-4-4-4-4 1.79-4 4 1.79 4 4 4zm0 2c-2.67 0-8 1.34-8 4v2h16v-2c0-2.66-5.33-4-8-4z"/></svg>
          Profil
        </div>
        <div class="s-nav-item" id="nav-pembayaran" onclick="switchTab('pembayaran')">
          <svg viewBox="0 0 24 24"><path d="M19 9h-4V3H9v6H5l7 7 7-7zM5 18v2h14v-2H5z"/></svg>
          Pembayaran
        </div>
      </nav>
      <div class="s-logout">
        <div class="s-logout-btn" onclick="doLogout()">
          <svg viewBox="0 0 24 24"><path d="M17 7l-1.41 1.41L18.17 11H8v2h10.17l-2.58 2.58L17 17l5-5zM4 5h8V3H4c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h8v-2H4V5z"/></svg>
          Keluar
        </div>
      </div>
    </aside>

    <!-- MAIN -->
    <div class="main-content">
      <!-- TAB: DASHBOARD -->
      <div id="tab-dashboard">
        <div class="welcome-card">
          <h2>Selamat Datang</h2>
          <div class="sub-name" id="wc-name">Wafiq Azizah asmad</div>
          <div id="status-badge" class="badge badge-orange" style="margin-bottom:14px;">Belum Lengkap</div>
          <div class="progress-bar-wrap">
            <div class="progress-label"><span>Progress Pendaftaran</span><span id="progress-pct">0%</span></div>
            <div class="progress-track"><div class="progress-fill" id="progress-fill" style="width:0%"></div></div>
          </div>
        </div>
        <div class="checklist-card">
          <h3>Checklist Pendaftaran</h3>
          <!-- ITEM 1: ISI PROFIL -->
          <div class="check-item" id="ci-profil" style="border-color:var(--orange);">
            <div class="check-circle" id="cc-profil"></div>
            <div class="check-body" style="flex:1;">
              <div class="title">
                <svg viewBox="0 0 24 24"><path d="M12 12c2.21 0 4-1.79 4-4s-1.79-4-4-4-4 1.79-4 4 1.79 4 4 4zm0 2c-2.67 0-8 1.34-8 4v2h16v-2c0-2.66-5.33-4-8-4z"/></svg>
                Isi Profil
              </div>
              <div class="desc" id="ci-profil-desc">Lengkapi data profil Anda (Nama, Sekolah, No HP, Alamat)</div>
              <div id="ci-profil-btn">
                <button class="btn btn-orange" style="font-size:13px;padding:7px 16px;" onclick="switchTab('profil')">Isi Profil</button>
              </div>
            </div>
          </div>
          <!-- ITEM 2: UPLOAD PEMBAYARAN -->
          <div class="check-item" id="ci-bayar">
            <div class="check-circle" id="cc-bayar"></div>
            <div class="check-body" style="flex:1;">
              <div class="title">
                <svg viewBox="0 0 24 24"><path d="M19 9h-4V3H9v6H5l7 7 7-7zM5 18v2h14v-2H5z"/></svg>
                Upload Pembayaran
              </div>
              <div class="desc" id="ci-bayar-desc">Lengkapi profil terlebih dahulu</div>
              <div id="ci-bayar-btn" class="hidden">
                <button class="btn btn-orange" style="font-size:13px;padding:7px 16px;" onclick="switchTab('pembayaran')">Upload Bukti</button>
              </div>
            </div>
          </div>
    <div class="alert alert-orange" id="dash-info">
            Silakan lengkapi data profil Anda untuk melanjutkan proses pendaftaran.
          </div>
        </div>

        <div class="checklist-card" style="margin-top:20px;">
          <h3>Tentang Olimpiade Sains FST Unpatti</h3>
          <p style="color:var(--text-gray);line-height:1.7;font-size:14px;margin-top:8px;">
            Olimpiade Sains FST (OS FST) adalah kompetisi sains tahunan yang diselenggarakan oleh Fakultas Sains dan Teknologi Universitas Pattimura untuk siswa jenjang SD, SMP, dan SMA/Sederajat se-Provinsi Maluku. Bidang yang dilombakan meliputi Matematika, Fisika, Kimia, Biologi, dan Komputer. Pemenang dari setiap jenjang berkesempatan mewakili Provinsi Maluku pada ajang olimpiade tingkat nasional.
          </p>
          <p style="color:var(--text-gray);line-height:1.7;font-size:14px;margin-top:10px;">
            Pastikan data profil dan bukti pembayaran Anda sudah lengkap dan benar agar proses verifikasi dapat berjalan lancar. Jika ada kendala, silakan hubungi panitia melalui kontak yang tersedia.
          </p>
        </div>
      </div>


      <!-- TAB: PROFIL -->
      <div id="tab-profil" class="hidden">
        <div class="section-card">
          <h2>Profil Peserta</h2>
          <div class="desc">Lengkapi data profil Anda untuk melanjutkan pendaftaran</div>
          <div class="field">
            <label>Nama Lengkap</label>
            <input type="text" id="p-nama" placeholder="Nama lengkap">
          </div>
          <div class="field">
            <label>Asal Sekolah</label>
            <input type="text" id="p-sekolah" placeholder="Nama sekolah">
          </div>
          <div class="field">
            <label>Nomor HP</label>
            <input type="text" id="p-hp" placeholder="Nomor HP aktif">
          </div>
          <div class="field">
            <label>Alamat</label>
            <input type="text" id="p-alamat" placeholder="Alamat lengkap">
          </div>
          <div class="field">
           <label>Bidang Lomba</label>
           <select id="p-bidang">
              <option value="">-- Pilih Bidang Lomba --</option>
              <option value="Matematika">Matematika</option>
              <option value="Fisika">Fisika</option>
              <option value="Kimia">Kimia</option>
              <option value="Biologi">Biologi</option>
              <option value="Komputer">Komputer</option>
            </select>
          </div>
          <div class="btn-row">
            <button class="btn btn-orange" onclick="saveProfil()">Simpan</button>
            <button class="btn btn-outline" onclick="switchTab('dashboard')">Batal</button>
          </div>
          <div class="alert alert-orange" style="margin-top:16px;">
            Pastikan semua data yang Anda masukkan sudah benar. Data ini akan digunakan untuk proses verifikasi.
          </div>
        </div>
      </div>

      <!-- TAB: PEMBAYARAN -->
      <div id="tab-pembayaran" class="hidden">
        <div class="section-card">
          <h2>Upload Bukti Pembayaran</h2>
          <div class="desc">Upload bukti transfer pembayaran pendaftaran Anda</div>
          <div class="payment-info">
            <h3>Informasi Pembayaran</h3>
            <div class="payment-row"><span class="lbl">Biaya Pendaftaran</span><span class="val">Rp 100.000</span></div>
            <div class="payment-row"><span class="lbl">Bank</span><span class="val">BNI</span></div>
            <div class="payment-row"><span class="lbl">No. Rekening</span><span class="val">1234567890</span></div>
            <div class="payment-row"><span class="lbl">Atas Nama</span><span class="val">Panitia Olimpiade Sains FST</span></div>
          </div>
          <div id="bayar-existing" class="hidden" style="margin-bottom:16px;"></div>
          <div id="upload-area">
            <label class="upload-drop" for="file-input">
              <input type="file" id="file-input" accept="image/*,.pdf" onchange="handleFileSelect(event)">
              <svg viewBox="0 0 24 24" style="width:32px;height:32px;fill:var(--text-gray);margin-bottom:8px;"><path d="M19 9h-4V3H9v6H5l7 7 7-7zM5 18v2h14v-2H5z"/></svg>
              <div style="font-size:14px;color:var(--text-gray);">Klik untuk memilih file atau drag & drop</div>
              <div style="font-size:12px;color:#9CA3AF;margin-top:4px;">JPG, PNG, PDF maksimal 5MB</div>
            </label>
          </div>
          <div id="file-preview" class="hidden">
            <div class="upload-preview">
              <div class="payment-row"><span class="lbl">Waktu</span><span class="val" style="font-size:14px;font-weight:600;">7:54 AM</span></div>
              <div class="payment-row"><span class="lbl">Tanggal</span><span class="val" style="font-size:14px;font-weight:600;">5 Sep 2021</span></div>
              <div class="payment-row"><span class="lbl">ID Transaksi</span><span class="val" style="font-size:14px;font-weight:600;">0220210905003399n...</span></div>
            </div>
            <div class="file-item" style="margin-bottom:16px;">
              <svg viewBox="0 0 24 24"><path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-5V3.5L18.5 9H13z"/></svg>
              <div>
                <div class="fname" id="file-name">bukti.jpeg</div>
                <div class="fsub">Bukti pembayaran</div>
              </div>
              <button class="file-remove" onclick="removeFile()">×</button>
            </div>
          </div>
          <div class="btn-row" id="bayar-btn-row">
            <button class="btn btn-orange" onclick="uploadBayar()">Upload Bukti</button>
            <button class="btn btn-outline" onclick="switchTab('dashboard')">Batal</button>
          </div>
        </div>
      </div>
    </div>
  </div>
  <button class="help-btn">?</button>
</div>


