      <div class="s-logo">
        <div class="logo-icon" style="width:36px;height:36px;background:linear-gradient(135deg,#F97316,#FB923C);">
          <svg viewBox="0 0 24 24" style="fill:white;"><path d="M12 1L3 5v6c0 5.55 3.84 10.74 9 12 5.16-1.26 9-6.45 9-12V5l-9-4z"/></svg>
        </div>
        <div class="logo-text"><span class="name">Admin<br>Portal</span><span class="sub">FST</span></div>
      </div>
      <div class="s-user">
        <div class="s-user-avatar" style="background:#FFF7ED;">
          <svg viewBox="0 0 24 24" style="fill:var(--orange);"><path d="M12 1L3 5v6c0 5.55 3.84 10.74 9 12 5.16-1.26 9-6.45 9-12V5l-9-4z"/></svg>
        </div>
        <div><div class="s-user-name">Administrator</div><div class="s-user-role">Admin</div></div>
      </div>
      <nav class="s-nav">
        <div class="s-nav-item" onclick="showPage('page-admin-dashboard')">
          <svg viewBox="0 0 24 24"><path d="M3 13h8V3H3v10zm0 8h8v-6H3v6zm10 0h8V11h-8v10zm0-18v6h8V3h-8z"/></svg>
