        </div>
      </nav>
      <div class="s-logout">
        <div class="s-logout-btn" onclick="doAdminLogout()">
          <svg viewBox="0 0 24 24"><path d="M17 7l-1.41 1.41L18.17 11H8v2h10.17l-2.58 2.58L17 17l5-5zM4 5h8V3H4c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h8v-2H4V5z"/></svg>
          Keluar
        </div>
      </div>
    </aside>
    <div class="main-content" style="padding:0;">
      <div class="detail-header">
        <button class="back-btn" onclick="showPage('page-admin-dashboard')">
          <svg viewBox="0 0 24 24" style="width:16px;height:16px;fill:currentColor;"><path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/></svg>
