          </div>
          <div style="color:var(--text-gray);font-size:14px;margin-bottom:20px;">Informasi lengkap peserta olimpiade</div>

          <div style="background:var(--gray-bg);border-radius:10px;padding:20px;margin-bottom:20px;">
            <div style="font-size:14px;font-weight:700;margin-bottom:14px;">Informasi Peserta</div>
            <div class="info-item">
              <div class="info-icon"><svg viewBox="0 0 24 24"><path d="M12 12c2.21 0 4-1.79 4-4s-1.79-4-4-4-4 1.79-4 4 1.79 4 4 4zm0 2c-2.67 0-8 1.34-8 4v2h16v-2c0-2.66-5.33-4-8-4z"/></svg></div>
              <div><div class="info-lbl">Nama Lengkap</div><div class="info-val" id="d-nama">-</div></div>
            </div>
            <div class="info-item">
              <div class="info-icon"><svg viewBox="0 0 24 24"><path d="M20 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V6c0-1.1-.9-2-2-2zm0 4l-8 5-8-5V6l8 5 8-5v2z"/></svg></div>
              <div><div class="info-lbl">Email</div><div class="info-val" id="d-email">-</div></div>
            </div>
            <div class="info-item">
              <div class="info-icon"><svg viewBox="0 0 24 24"><path d="M12 3L1 9l4 2.18v6L12 21l7-3.82v-6l2-1.09V17h2V9L12 3z"/></svg></div>
              <div><div class="info-lbl">Asal Sekolah</div><div class="info-val" id="d-sekolah">-</div></div>
            </div>
            <div class="info-item">
              <div class="info-icon"><svg viewBox="0 0 24 24"><path d="M6.62 10.79c1.44 2.83 3.76 5.14 6.59 6.59l2.2-2.2c.27-.27.67-.36 1.02-.24 1.12.37 2.33.57 3.57.57.55 0 1 .45 1 1V20c0 .55-.45 1-1 1-9.39 0-17-7.61-17-17 0-.55.45-1 1-1h3.5c.55 0 1 .45 1 1 0 1.25.2 2.45.57 3.57.11.35.03.74-.25 1.02l-2.2 2.2z"/></svg></div>
              <div><div class="info-lbl">Nomor HP</div><div class="info-val" id="d-hp">-</div></div>
            </div>
            <div class="info-item">
              <div class="info-icon"><svg viewBox="0 0 24 24"><path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7zm0 9.5c-1.38 0-2.5-1.12-2.5-2.5s1.12-2.5 2.5-2.5 2.5 1.12 2.5 2.5-1.12 2.5-2.5 2.5z"/></svg></div>
              <div><div class="info-lbl">Alamat</div><div class="info-val" id="d-alamat">-</div></div>
            </div>
          </div>

          <div style="background:var(--gray-bg);border-radius:10px;padding:20px;margin-bottom:20px;">
            <div style="font-size:14px;font-weight:700;margin-bottom:14px;">
              <svg viewBox="0 0 24 24" style="width:16px;height:16px;fill:var(--text-gray);vertical-align:middle;margin-right:6px;"><path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-5V3.5L18.5 9H13z"/></svg>
              Bukti Pembayaran
            </div>
            <div id="bukti-container" style="background:white;border-radius:8px;padding:24px;text-align:center;color:var(--text-gray);font-size:14px;">
              Belum ada bukti pembayaran diupload
            </div>
          </div>

          <div id="verif-section">
            <div style="font-size:14px;font-weight:700;margin-bottom:12px;">Verifikasi Pendaftaran</div>
            <div class="verif-btns">
              <button class="btn btn-green" onclick="approveParticipant()" style="display:flex;align-items:center;gap:6px;">
                <svg viewBox="0 0 24 24" style="width:16px;height:16px;fill:white;"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-2 15l-5-5 1.41-1.41L10 14.17l7.59-7.59L19 8l-9 9z"/></svg>
                Setujui
              </button>
              <button class="btn btn-red" onclick="rejectParticipant()" style="display:flex;align-items:center;gap:6px;">
                <svg viewBox="0 0 24 24" style="width:16px;height:16px;fill:white;"><path d="M12 2C6.47 2 2 6.47 2 12s4.47 10 10 10 10-4.47 10-10S17.53 2 12 2zm5 13.59L15.59 17 12 13.41 8.41 17 7 15.59 10.59 12 7 8.41 8.41 7 12 10.59 15.59 7 17 8.41 13.41 12 17 15.59z"/></svg>
                Tolak
              </button>
            </div>
          </div>
          <div id="approved-msg" class="hidden">
            <div class="alert alert-green">Peserta ini telah disetujui</div>
          </div>
          <div id="rejected-msg" class="hidden">
            <div class="alert" style="background:#FEF2F2;color:var(--red);border:1px solid #FECACA;">Peserta ini telah ditolak</div>
          </div>
        </div>
      </div>
    </div>
  </div>
  <button class="help-btn">?</button>
</div>

